defineproc.example:
defineproc relerr { newVal RefVal name my_err } {
    upvar my_err fl
    set denom [expr abs($newVal)+abs($RefVal)+1e-20]
    set deviation [expr 100*abs(($RefVal - $newVal)/$denom)]
}

fproc.example:
fproc scale_pitch {value factor} {
    set localFromFproc [expr {$value * $factor}]
    return $localFromFproc
}

